1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
12	const BLOCK_SIZE = 3;
13	const BLOCK_PREMIUM = 60;
14	const COMPONENT_PREMIUM = 25;
15	
16	const calculateQuotePremium = (items: any[]): { premium: number } => {
17	  const componentCounts: Record<string, number> = {};
18	  let basePremium = 0;
19	
20	  for (const item of items) {
21	    if (COMPONENT_TYPES.has(item.type)) {
22	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
23	    } else {
24	      basePremium += BASE_PREMIUMS[item.type] || 0;
25	    }
26	  }
27	
28	  for (const count of Object.values(componentCounts)) {
29	    if (count === BLOCK_SIZE) {
30	      basePremium += BLOCK_PREMIUM;
31	    } else {
32	      basePremium += count * COMPONENT_PREMIUM;
33	    }
34	  }
35	
36	  return { premium: basePremium + PROCESSING_FEE };
37	};
38	
39	export const processScenario = (scenario: any): any => {
40	  const results = scenario.steps.map((step: any) => calculateQuotePremium(step.items));
41	  return { results };
42	};
